  1	import * as React from 'react';
  2	import { ExternalLinkAltIcon } from '@patternfly/react-icons';
  3	import { GraphElement, Node } from '@patternfly/react-topology';
  4	import { InOutRateTableGrpc, InOutRateTableHttp } from '../../components/SummaryPanel/InOutRateTable';
  5	import { RequestChart, StreamChart } from '../../components/SummaryPanel/RpsChart';
  6	import {
  7	  DecoratedGraphNodeData,
  8	  NodeAttr,
  9	  NodeType,
 10	  Protocol,
 11	  SummaryPanelPropType,
 12	  TrafficRate
 13	} from '../../types/Graph';
 14	import { getAccumulatedTrafficRateGrpc, getAccumulatedTrafficRateHttp } from '../../utils/TrafficRate';
 15	import { renderBadgedLink, renderHealth } from './SummaryLink';
 16	import {
 17	  shouldRefreshData,
 18	  getNodeMetrics,
 19	  getNodeMetricType,
 20	  renderNoTraffic,
 21	  hr,
 22	  summaryPanel,
 23	  mergeMetricsResponses,
 24	  getDatapoints,
 25	  getTitle
 26	} from './SummaryPanelCommon';
 27	import { IstioMetricsMap, Datapoint, Labels } from '../../types/Metrics';
 28	import { Reporter } from '../../types/MetricsOptions';
 29	import { CancelablePromise, makeCancelablePromise } from '../../utils/CancelablePromises';
 30	import { KialiIcon } from 'config/KialiIcon';
 31	import { getOptions, clickHandler } from 'pages/Graph/ContextMenu/NodeContextMenu';
 32	import { PFBadge, PFBadges } from 'components/Pf/PfBadges';
 33	import { edgesIn, edgesOut, select, selectAnd, selectOr } from 'helpers/GraphHelpers';
 34	import { classes } from 'typestyle';
 35	import { panelBodyStyle, panelHeadingStyle, panelStyle } from './SummaryPanelStyle';
 36	import { isMultiCluster, serverConfig } from 'config';
 37	import {
 38	  Dropdown,
 39	  DropdownGroup,
 40	  DropdownItem,
 41	  DropdownList,
 42	  MenuToggle,
 43	  MenuToggleElement
 44	} from '@patternfly/react-core';
 45	import { kebabToggleStyle } from 'styles/DropdownStyles';
 46	import { kialiStyle } from 'styles/StyleUtils';
 47	import { ApiResponse } from 'types/Api';
 48	
 49	type SummaryPanelAppBoxMetricsState = {
 50	  grpcReceivedIn: Datapoint[];
 51	  grpcReceivedOut: Datapoint[];
 52	  grpcRequestErrIn: Datapoint[];
 53	  grpcRequestErrOut: Datapoint[];
 54	  grpcRequestIn: Datapoint[];
 55	  grpcRequestOut: Datapoint[];
 56	  grpcSentIn: Datapoint[];
 57	  grpcSentOut: Datapoint[];
 58	  httpRequestErrIn: Datapoint[];
 59	  httpRequestErrOut: Datapoint[];
 60	  httpRequestIn: Datapoint[];
 61	  httpRequestOut: Datapoint[];
 62	  tcpReceivedIn: Datapoint[];
 63	  tcpReceivedOut: Datapoint[];
 64	  tcpSentIn: Datapoint[];
 65	  tcpSentOut: Datapoint[];
 66	};
 67	
 68	type SummaryPanelAppBoxState = SummaryPanelAppBoxMetricsState & {
 69	  appBox: any;
 70	  isOpen: boolean;
 71	  loading: boolean;
 72	  metricsLoadError: string | null;
 73	};
 74	
 75	const defaultMetricsState: SummaryPanelAppBoxMetricsState = {
 76	  grpcReceivedIn: [],
 77	  grpcReceivedOut: [],
 78	  grpcRequestErrIn: [],
 79	  grpcRequestErrOut: [],
 80	  grpcRequestIn: [],
 81	  grpcRequestOut: [],
 82	  grpcSentIn: [],
 83	  grpcSentOut: [],
 84	  httpRequestErrIn: [],
 85	  httpRequestErrOut: [],
 86	  httpRequestIn: [],
 87	  httpRequestOut: [],
 88	  tcpReceivedIn: [],
 89	  tcpReceivedOut: [],
 90	  tcpSentIn: [],
 91	  tcpSentOut: []
 92	};
 93	
 94	const defaultState: SummaryPanelAppBoxState = {
 95	  appBox: null,
 96	  isOpen: false,
 97	  loading: false,
 98	  metricsLoadError: null,
 99	  ...defaultMetricsState
100	};
101	
102	const nodeInfoStyle = kialiStyle({
103	  display: 'flex',
104	  marginTop: '0.25rem'
105	});
106	
107	export class SummaryPanelAppBox extends React.Component<SummaryPanelPropType, SummaryPanelAppBoxState> {
108	  private metricsPromise?: CancelablePromise<ApiResponse<IstioMetricsMap>[]>;
109	  private readonly mainDivRef: React.RefObject<HTMLDivElement>;
110	
111	  constructor(props: SummaryPanelPropType) {
112	    super(props);
113	    this.state = { ...defaultState };
114	
115	    this.mainDivRef = React.createRef<HTMLDivElement>();
116	  }
117	
118	  static getDerivedStateFromProps(
119	    props: SummaryPanelPropType,
120	    state: SummaryPanelAppBoxState
121	  ): Partial<SummaryPanelAppBoxState> | null {
122	    // if the summaryTarget (i.e. selected appBox) has changed, then init the state and set to loading. The loading
123	    // will actually be kicked off after the render (in componentDidMount/Update).
124	    return props.data.summaryTarget !== state.appBox
125	      ? { appBox: props.data.summaryTarget, loading: true, ...defaultMetricsState }
126	      : null;
127	  }
128	
129	  componentDidMount(): void {
130	    this.updateCharts(this.props);
131	  }
132	
133	  componentDidUpdate(prevProps: SummaryPanelPropType): void {
134	    if (prevProps.data.summaryTarget !== this.props.data.summaryTarget) {
135	      if (this.mainDivRef.current) {
136	        this.mainDivRef.current.scrollTop = 0;
137	      }
138	    }
139	
140	    if (shouldRefreshData(prevProps, this.props)) {
141	      this.updateCharts(this.props);
142	    }
143	  }
144	
145	  componentWillUnmount(): void {
146	    if (this.metricsPromise) {
147	      this.metricsPromise.cancel();
148	    }
149	  }
150	
151	  render(): React.ReactNode {
152	    const appBox = this.props.data.summaryTarget as GraphElement;
153	    const nodeData = appBox.getData();
154	
155	    const serviceList = this.renderServiceList(appBox);
156	    const workloadList = this.renderWorkloadList(appBox);
157	    const hasGrpc = this.hasGrpcTraffic(appBox);
158	    const isGrpcRequests = hasGrpc && this.isGrpcRequests();
159	    const hasGrpcIn = hasGrpc && this.hasGrpcIn(appBox);
160	    const hasGrpcOut = hasGrpc && this.hasGrpcOut(appBox);
161	    const hasHttp = this.hasHttpTraffic(appBox);
162	    const hasHttpIn = hasHttp && this.hasHttpIn(appBox);
163	    const hasHttpOut = hasHttp && this.hasHttpOut(appBox);
164	    const hasTcp = this.hasTcpTraffic(appBox);
165	    const hasTcpIn = hasTcp && this.hasTcpIn(appBox);
166	    const hasTcpOut = hasTcp && this.hasTcpOut(appBox);
167	
168	    const options = getOptions(nodeData);
169	    const items = [
170	      <DropdownGroup key="show" label="Show">
171	        {options.map((o, i) => {
172	          return (
173	            <DropdownItem key={`option-${i}`} onClick={() => clickHandler(o, this.props.kiosk)}>
174	              {o.text} {o.target === '_blank' && <ExternalLinkAltIcon />}
175	            </DropdownItem>
176	          );
177	        })}
178	      </DropdownGroup>
179	    ];
180	
181	    const firstBadge = isMultiCluster ? (
182	      <>
183	        <PFBadge badge={PFBadges.Cluster} size="sm" style={{ marginBottom: '0.125rem' }} />
184	        {nodeData.cluster}
185	      </>
186	    ) : (
187	      <>
188	        <PFBadge badge={PFBadges.Namespace} size="sm" style={{ marginBottom: '0.125rem' }} />
189	        {nodeData.namespace}
190	      </>
191	    );
192	
193	    const secondBadge = isMultiCluster ? (
194	      <div>
195	        <PFBadge badge={PFBadges.Namespace} size="sm" style={{ marginBottom: '0.125rem' }} />
196	        {nodeData.namespace}
197	      </div>
198	    ) : (
199	      <></>
200	    );
201	
202	    return (
203	      <div ref={this.mainDivRef} className={classes(panelStyle, summaryPanel)}>
204	        <div className={panelHeadingStyle}>
205	          {getTitle('Application')}
206	
207	          <span>
208	            {firstBadge}
209	
210	            {options.length > 0 && (
211	              <Dropdown
212	                id="summary-appbox-actions"
213	                toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
214	                  <MenuToggle
215	                    ref={toggleRef}
216	                    id="summary-appbox-kebab"
217	                    className={kebabToggleStyle}
218	                    aria-label="Actions"
219	                    variant="plain"
220	                    onClick={() => this.onToggleActions(!this.state.isOpen)}
221	                    isExpanded={this.state.isOpen}
222	                    style={{ float: 'right' }}
223	                  >
224	                    <KialiIcon.KebabToggle />
225	                  </MenuToggle>
226	                )}
227	                isOpen={this.state.isOpen}
228	                onOpenChange={(isOpen: boolean) => this.onToggleActions(isOpen)}
229	                popperProps={{ position: 'right' }}
230	              >
231	                <DropdownList>{items}</DropdownList>
232	              </Dropdown>
233	            )}
234	
235	            {secondBadge}
236	
237	            <div className={nodeInfoStyle}>
238	              {renderBadgedLink(nodeData)}
239	              {renderHealth(nodeData.health)}
240	            </div>
241	          </span>
242	
243	          <div>
244	            {this.renderBadgeSummary(appBox)}
245	            {serviceList.length > 0 && <div>{serviceList}</div>}
246	            {workloadList.length > 0 && <div> {workloadList}</div>}
247	          </div>
248	        </div>
249	
250	        <div className={panelBodyStyle}>
251	          {hasGrpc && isGrpcRequests && (
252	            <>
253	              {this.renderGrpcRequests(appBox)}
254	              {hr()}
255	            </>
256	          )}
257	
258	          {hasHttp && (
259	            <>
260	              {this.renderHttpRequests(appBox)}
261	              {hr()}
262	            </>
263	          )}
264	
265	          <div>
266	            {this.renderSparklines(appBox)}
267	            {hr()}
268	          </div>
269	
270	          {hasGrpc && !hasGrpcIn && renderNoTraffic('gRPC inbound')}
271	          {hasGrpc && !hasGrpcOut && renderNoTraffic('gRPC outbound')}
272	          {!hasGrpc && renderNoTraffic('gRPC')}
273	          {hasHttp && !hasHttpIn && renderNoTraffic('HTTP inbound')}
274	          {hasHttp && !hasHttpOut && renderNoTraffic('HTTP outbound')}
275	          {!hasHttp && renderNoTraffic('HTTP')}
276	          {hasTcp && !hasTcpIn && renderNoTraffic('TCP inbound')}
277	          {hasTcp && !hasTcpOut && renderNoTraffic('TCP outbound')}
278	          {!hasTcp && renderNoTraffic('TCP')}
279	        </div>
280	      </div>
281	    );
282	  }
283	
284	  private onToggleActions = (isExpanded: boolean): void => {
285	    this.setState({ isOpen: isExpanded });
286	  };
287	
288	  private updateCharts = (props: SummaryPanelPropType): void => {
289	    const appBox = props.data.summaryTarget as GraphElement;
290	    const nodeData = appBox.getData() as DecoratedGraphNodeData;
291	    const nodeMetricType = getNodeMetricType(nodeData);
292	    const isGrpcRequests = this.isGrpcRequests();
293	
294	    if (this.metricsPromise) {
295	      this.metricsPromise.cancel();
296	      this.metricsPromise = undefined;
297	    }
298	
299	    if (!this.hasGrpcTraffic(appBox) && !this.hasHttpTraffic(appBox) && !this.hasTcpTraffic(appBox)) {
300	      this.setState({ loading: false });
301	      return;
302	    }
303	
304	    // appBoxes are never root nodes, so always look for inbound traffic
305	    let promiseInRps: Promise<ApiResponse<IstioMetricsMap>> = Promise.resolve({ data: {} });
306	    let promiseInStream: Promise<ApiResponse<IstioMetricsMap>> = Promise.resolve({ data: {} });
307	
308	    if (this.hasHttpIn(appBox) || (this.hasGrpcIn(appBox) && isGrpcRequests)) {
309	      const filtersRps = ['request_count', 'request_error_count'];
310	
311	      promiseInRps = getNodeMetrics(
312	        nodeMetricType,
313	        nodeData,
314	        props,
315	        filtersRps,
316	        'inbound',
317	        'destination',
318	        serverConfig.ambientEnabled, // TODO change to nodeData.isAmbient when it is set for all node types
319	        undefined,
320	        undefined,
321	        ['request_protocol']
322	      );
323	    }
324	
325	    if (this.hasTcpIn(appBox) || (this.hasGrpcIn(appBox) && !isGrpcRequests)) {
326	      const filtersStream = [] as string[];
327	
328	      if (this.hasGrpcIn(appBox) && !isGrpcRequests) {
329	        filtersStream.push('grpc_sent', 'grpc_received');
330	      }
331	
332	      if (this.hasTcpIn(appBox)) {
333	        filtersStream.push('tcp_sent', 'tcp_received');
334	      }
335	
336	      if (filtersStream.length > 0) {
337	        const byLabelsStream = nodeData.isOutside ? ['source_workload_namespace'] : [];
338	
339	        promiseInStream = getNodeMetrics(
340	          nodeMetricType,
341	          nodeData,
342	          props,
343	          filtersStream,
344	          'inbound',
345	          'source',
346	          serverConfig.ambientEnabled, // TODO change to "nodeData.isAmbient" when it is set for this node type
347	          undefined,
348	          undefined,
349	          byLabelsStream
350	        );
351	      }
352	    }
353	
354	    const promiseIn = mergeMetricsResponses([promiseInRps, promiseInStream]);
355	    let promiseOut: Promise<ApiResponse<IstioMetricsMap>> = Promise.resolve({ data: {} });
356	
357	    // Ignore outbound traffic if it is a non-root (appbox is always non-root) outsider (because they have no outbound edges)
358	    if (!nodeData.isOutside) {
359	      const filters = [] as string[];
360	      if (this.hasHttpOut(appBox) || (this.hasGrpcOut(appBox) && isGrpcRequests)) {
361	        filters.push('request_count', 'request_error_count');
362	      }
363	
364	      if (this.hasGrpcOut(appBox) && !isGrpcRequests) {
365	        filters.push('grpc_sent', 'grpc_received');
366	      }
367	
368	      if (this.hasTcpOut(appBox)) {
369	        filters.push('tcp_sent', 'tcp_received');
370	      }
371	
372	      if (filters.length > 0) {
373	        // use source metrics for outbound, except for:
374	        // - istio namespace nodes (no source telemetry)
375	        const reporter: Reporter = nodeData.isIstio ? 'destination' : 'source';
376	
377	        // note: request_protocol is not a valid byLabel for tcp/grpc-message filters but it is ignored by prometheus
378	        const byLabels = nodeData.isOutside
379	          ? ['destination_service_namespace', 'request_protocol']
380	          : ['request_protocol'];
381	
382	        promiseOut = getNodeMetrics(
383	          nodeMetricType,
384	          nodeData,
385	          props,
386	          filters,
387	          'outbound',
388	          reporter,
389	          serverConfig.ambientEnabled, // TODO change to "nodeData.isAmbient" when it is set for this node type
390	          undefined,
391	          undefined,
392	          byLabels
393	        );
394	      }
395	    }
396	
397	    // use dest metrics for inbound
398	    this.metricsPromise = makeCancelablePromise(Promise.all([promiseOut, promiseIn]));
399	
400	    this.metricsPromise.promise
401	      .then((responses: ApiResponse<IstioMetricsMap>[]) => {
402	        const comparator = nodeData.isOutside
403	          ? (labels: Labels, protocol?: Protocol) => {
404	              return protocol ? labels.request_protocol === protocol : true;
405	            }
406	          : (labels: Labels, protocol?: Protocol) => {
407	              if (protocol && labels.request_protocol !== protocol) {
408	                return false;
409	              }
410	
411	              if (
412	                labels.destination_service_namespace &&
413	                !this.isActiveNamespace(labels.destination_service_namespace)
414	              ) {
415	                return false;
416	              }
417	
418	              if (labels.source_workload_namespace && !this.isActiveNamespace(labels.source_workload_namespace)) {
419	                return false;
420	              }
421	
422	              return true;
423	            };
424	
425	        const metricsOut = responses[0].data;
426	        const metricsIn = responses[1].data;
427	
428	        this.setState({
429	          loading: false,
430	          grpcRequestErrIn: getDatapoints(metricsIn.request_error_count, comparator, Protocol.GRPC),
431	          grpcRequestErrOut: getDatapoints(metricsOut.request_error_count, comparator, Protocol.GRPC),
432	          grpcReceivedIn: getDatapoints(metricsIn.grpc_received, comparator),
433	          grpcReceivedOut: getDatapoints(metricsOut.grpc_received, comparator),
434	          grpcRequestIn: getDatapoints(metricsIn.request_count, comparator, Protocol.GRPC),
435	          grpcRequestOut: getDatapoints(metricsOut.request_count, comparator, Protocol.GRPC),
436	          grpcSentIn: getDatapoints(metricsIn.grpc_sent, comparator),
437	          grpcSentOut: getDatapoints(metricsOut.grpc_sent, comparator),
438	          httpRequestErrIn: getDatapoints(metricsIn.request_error_count, comparator, Protocol.HTTP),
439	          httpRequestErrOut: getDatapoints(metricsOut.request_error_count, comparator, Protocol.HTTP),
440	          httpRequestIn: getDatapoints(metricsIn.request_count, comparator, Protocol.HTTP),
441	          httpRequestOut: getDatapoints(metricsOut.request_count, comparator, Protocol.HTTP),
442	          tcpReceivedOut: getDatapoints(metricsOut.tcp_received, comparator),
443	          tcpReceivedIn: getDatapoints(metricsIn.tcp_received, comparator),
444	          tcpSentIn: getDatapoints(metricsIn.tcp_sent, comparator),
445	          tcpSentOut: getDatapoints(metricsOut.tcp_sent, comparator)
446	        });
447	      })
448	      .catch(error => {
449	        if (error.isCanceled) {
450	          console.debug('SummaryPanelAppBox: Ignore fetch error (canceled).');
451	          return;
452	        }
453	        const errorMsg = error.response && error.response.data.error ? error.response.data.error : error.message;
454	
455	        this.setState({
456	          loading: false,
457	          metricsLoadError: errorMsg,
458	          ...defaultMetricsState
459	        });
460	      });
461	
462	    this.setState({ loading: true, metricsLoadError: null });
463	  };
464	
465	  private isActiveNamespace = (namespace: string): boolean => {
466	    if (!namespace) {
467	      return false;
468	    }
469	
470	    for (const ns of this.props.namespaces) {
471	      if (ns.name === namespace) {
472	        return true;
473	      }
474	    }
475	
476	    return false;
477	  };
478	
479	  private renderBadgeSummary = (appBox): React.ReactNode => {
480	    const appBoxData = appBox.getData();
481	
482	    let hasCB: boolean = appBoxData[NodeAttr.hasCB] === true;
483	    let hasVS: boolean = appBoxData[NodeAttr.hasVS] === true;
484	
485	    const appBoxChildren = appBox.getAllNodeChildren();
486	
487	    selectOr(appBoxChildren, [
488	      [{ prop: NodeAttr.hasCB, op: 'truthy' }],
489	      [{ prop: NodeAttr.hasVS, op: 'truthy' }]
490	    ]).forEach(n => {
491	      hasCB = hasCB || !!n.getData()[NodeAttr.hasCB];
492	      hasVS = hasVS || !!n.getData()[NodeAttr.hasVS];
493	    });
494	
495	    return (
496	      <div style={{ marginTop: '0.5rem', marginBottom: '0.5rem' }}>
497	        {hasCB && (
498	          <div>
499	            <KialiIcon.CircuitBreaker />
500	            <span style={{ paddingLeft: '0.25rem' }}>Has Circuit Breaker</span>
501	          </div>
502	        )}
503	
504	        {hasVS && (
505	          <div>
506	            <KialiIcon.VirtualService />
507	            <span style={{ paddingLeft: '0.25rem' }}>Has Virtual Service</span>
508	          </div>
509	        )}
510	      </div>
511	    );
512	  };
513	
514	  private renderGrpcRequests = (appBox): React.ReactNode => {
515	    // only consider the physical children to avoid inflated rates
516	    const appBoxChildren = appBox.getAllNodeChildren();
517	
518	    const validChildren = selectAnd(appBoxChildren, [
519	      { prop: NodeAttr.nodeType, op: '!=', val: NodeType.SERVICE },
520	      { prop: NodeAttr.nodeType, op: '!=', val: NodeType.AGGREGATE }
521	    ]);
522	
523	    const inbound = getAccumulatedTrafficRateGrpc(edgesIn(validChildren as Node[]));
524	    const outbound = getAccumulatedTrafficRateGrpc(edgesOut(validChildren as Node[]));
525	
526	    return (
527	      <InOutRateTableGrpc
528	        title="GRPC Traffic (requests per second):"
529	        inRate={inbound.rate}
530	        inRateGrpcErr={inbound.rateGrpcErr}
531	        inRateNR={inbound.rateNoResponse}
532	        outRate={outbound.rate}
533	        outRateGrpcErr={outbound.rateGrpcErr}
534	        outRateNR={outbound.rateNoResponse}
535	      />
536	    );
537	  };
538	
539	  private renderHttpRequests = (appBox): React.ReactNode => {
540	    // only consider the physical children to avoid inflated rates
541	    const appBoxChildren = appBox.getAllNodeChildren();
542	
543	    const validChildren = selectAnd(appBoxChildren, [
544	      { prop: NodeAttr.nodeType, op: '!=', val: NodeType.SERVICE },
545	      { prop: NodeAttr.nodeType, op: '!=', val: NodeType.AGGREGATE }
546	    ]);
547	
548	    const inbound = getAccumulatedTrafficRateHttp(edgesIn(validChildren as Node[]));
549	    const outbound = getAccumulatedTrafficRateHttp(edgesOut(validChildren as Node[]));
550	
551	    return (
552	      <InOutRateTableHttp
553	        title="HTTP (requests per second):"
554	        inRate={inbound.rate}
555	        inRate3xx={inbound.rate3xx}
556	        inRate4xx={inbound.rate4xx}
557	        inRate5xx={inbound.rate5xx}
558	        inRateNR={inbound.rateNoResponse}
559	        outRate={outbound.rate}
560	        outRate3xx={outbound.rate3xx}
561	        outRate4xx={outbound.rate4xx}
562	        outRate5xx={outbound.rate5xx}
563	        outRateNR={outbound.rateNoResponse}
564	      />
565	    );
566	  };
567	
568	  private renderSparklines = (appBox): React.ReactNode => {
569	    if (this.state.loading) {
570	      return <strong>Loading charts...</strong>;
571	    } else if (this.state.metricsLoadError) {
572	      return (
573	        <div>
574	          <KialiIcon.Warning /> <strong>Error loading metrics: </strong>
575	          {this.state.metricsLoadError}
576	        </div>
577	      );
578	    }
579	
580	    const hasGrpc = this.hasGrpcTraffic(appBox);
581	    const isGrpcRequests = hasGrpc && this.isGrpcRequests();
582	    const hasGrpcIn = hasGrpc && this.hasGrpcIn(appBox);
583	    const hasGrpcOut = hasGrpc && this.hasGrpcOut(appBox);
584	    const hasHttp = this.hasHttpTraffic(appBox);
585	    const hasHttpIn = hasHttp && this.hasHttpIn(appBox);
586	    const hasHttpOut = hasHttp && this.hasHttpOut(appBox);
587	    const hasTcp = this.hasTcpTraffic(appBox);
588	    const hasTcpIn = hasTcp && this.hasTcpIn(appBox);
589	    const hasTcpOut = hasTcp && this.hasTcpOut(appBox);
590	
591	    let grpcCharts: React.ReactNode, httpCharts: React.ReactNode, tcpCharts: React.ReactNode;
592	
593	    if (hasGrpc) {
594	      grpcCharts = isGrpcRequests ? (
595	        <>
596	          {hasGrpcIn && (
597	            <RequestChart
598	              key="grpc-inbound-request"
599	              label="gRPC - Inbound Request Traffic"
600	              dataRps={this.state.grpcRequestIn!}
601	              dataErrors={this.state.grpcRequestErrIn}
602	            />
603	          )}
604	
605	          {hasGrpcOut && (
606	            <RequestChart
607	              key="grpc-outbound-request"
608	              label="gRPC - Outbound Request Traffic"
609	              dataRps={this.state.grpcRequestOut}
610	              dataErrors={this.state.grpcRequestErrOut}
611	            />
612	          )}
613	        </>
614	      ) : (
615	        <>
616	          {hasGrpcIn && (
617	            <StreamChart
618	              label="gRPC - Inbound Traffic"
