568	  private renderSparklines = (appBox): React.ReactNode => {
569	    if (this.state.loading) {
570	      return <strong>Loading charts...</strong>;
571	    } else if (this.state.metricsLoadError) {
572	      return (
573	        <div>
574	          <KialiIcon.Warning /> <strong>Error loading metrics: </strong>
575	          {this.state.metricsLoadError}
576	        </div>
577	      );
578	    }
579	
580	    const hasGrpc = this.hasGrpcTraffic(appBox);
581	    const isGrpcRequests = hasGrpc && this.isGrpcRequests();
582	    const hasGrpcIn = hasGrpc && this.hasGrpcIn(appBox);
583	    const hasGrpcOut = hasGrpc && this.hasGrpcOut(appBox);
584	    const hasHttp = this.hasHttpTraffic(appBox);
585	    const hasHttpIn = hasHttp && this.hasHttpIn(appBox);
586	    const hasHttpOut = hasHttp && this.hasHttpOut(appBox);
587	    const hasTcp = this.hasTcpTraffic(appBox);
588	    const hasTcpIn = hasTcp && this.hasTcpIn(appBox);
589	    const hasTcpOut = hasTcp && this.hasTcpOut(appBox);
590	
591	    let grpcCharts: React.ReactNode, httpCharts: React.ReactNode, tcpCharts: React.ReactNode;
592	
593	    if (hasGrpc) {
594	      grpcCharts = isGrpcRequests ? (
595	        <>
596	          {hasGrpcIn && (
597	            <RequestChart
598	              key="grpc-inbound-request"
599	              label="gRPC - Inbound Request Traffic"
600	              dataRps={this.state.grpcRequestIn!}
601	              dataErrors={this.state.grpcRequestErrIn}
602	            />
603	          )}
604	
605	          {hasGrpcOut && (
606	            <RequestChart
607	              key="grpc-outbound-request"
608	              label="gRPC - Outbound Request Traffic"
609	              dataRps={this.state.grpcRequestOut}
610	              dataErrors={this.state.grpcRequestErrOut}
611	            />
612	          )}
613	        </>
614	      ) : (
615	        <>
616	          {hasGrpcIn && (
617	            <StreamChart
618	              label="gRPC - Inbound Traffic"
619	              receivedRates={this.state.grpcReceivedIn}
620	              sentRates={this.state.grpcSentIn}
621	              unit="messages"
622	            />
623	          )}
624	
625	          {hasGrpcOut && (
626	            <StreamChart
627	              label="gRPC - Outbound Traffic"
628	              receivedRates={this.state.grpcReceivedOut}
629	              sentRates={this.state.grpcSentOut}
630	              unit="messages"
631	            />
632	          )}
633	        </>
634	      );
635	    }
636	
637	    if (hasHttp) {
638	      httpCharts = (
639	        <>
640	          {hasHttpIn && (
641	            <RequestChart
642	              key="http-inbound-request"
643	              label="HTTP - Inbound Request Traffic"
644	              dataRps={this.state.httpRequestIn}
645	              dataErrors={this.state.httpRequestErrIn}
646	            />
647	          )}
648	
649	          {hasHttpOut && (
650	            <RequestChart
651	              key="http-outbound-request"
652	              label="HTTP - Outbound Request Traffic"
653	              dataRps={this.state.httpRequestOut}
654	              dataErrors={this.state.httpRequestErrOut}
655	            />
656	          )}
657	        </>
658	      );
659	    }
660	
661	    if (hasTcp) {
662	      tcpCharts = (
663	        <>
664	          {hasTcpIn && (
665	            <StreamChart
666	              key="tcp-inbound-request"
667	              label="TCP - Inbound Traffic"
668	              receivedRates={this.state.tcpReceivedIn}
669	              sentRates={this.state.tcpSentIn}
670	              unit="bytes"
671	            />
672	          )}
673	
674	          {hasTcpOut && (
675	            <StreamChart
676	              key="tcp-outbound-request"
677	              label="TCP - Outbound Traffic"
678	              receivedRates={this.state.tcpReceivedOut}
679	              sentRates={this.state.tcpSentOut}
680	              unit="bytes"
681	            />
682	          )}
683	        </>
684	      );
685	    }
686	
687	    return (
688	      <>
