696	  private renderServiceList = (appBox): React.ReactNode[] => {
697	    // likely 0 or 1 but support N in case of unanticipated labeling
698	    const serviceList: React.ReactNode[] = [];
699	
700	    const appBoxChildren = appBox.getAllNodeChildren();
701	
702	    select(appBoxChildren, { prop: NodeAttr.nodeType, val: NodeType.SERVICE }).forEach((serviceNode, i) => {
703	      const serviceNodeData = serviceNode.getData();
704	      serviceList.push(renderBadgedLink(serviceNodeData, NodeType.SERVICE));
705	
706	      const aggregates = selectAnd(appBoxChildren, [
707	        { prop: NodeAttr.nodeType, val: NodeType.AGGREGATE },
708	        { prop: NodeAttr.service, val: serviceNodeData.service }
709	      ]);
710	
711	      if (!!aggregates && aggregates.length > 0) {
712	        const aggregateList: React.ReactNode[] = [];
713	
714	        aggregates.forEach(aggregateNode => {
715	          const aggregateNodeData = aggregateNode.getData();
716	          aggregateList.push(renderBadgedLink(aggregateNodeData, NodeType.AGGREGATE));
717	        });
718	
719	        serviceList.push(<div key={`service-${i}`}>{aggregateList}</div>);
720	      }
721	    });
722	
723	    return serviceList;
724	  };
